1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number };
14	type Step = { op: string; items: Item[] };
15	type Customer = { yearsWithMHPCO: number };
16	type Input = { customer: Customer; steps: Step[] };
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_BASE_PREMIUM = 60;
20	const BLOCK_SIZE = 3;
21	
22	const withFirstInsurance = (base: number): number =>
23	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
24	
25	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
26	
27	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
28	
29	const groupByType = (items: Item[]): Map<string, Item[]> => {
30	  const groups = new Map<string, Item[]>();
31	  for (const item of items) {
32	    const group = groups.get(item.type) ?? [];
33	    group.push(item);
34	    groups.set(item.type, group);
35	  }
36	  return groups;
37	};
38	
39	const componentGroupBasePremium = (group: Item[]): number =>
40	  group.length === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : group.reduce((sum, item) => sum + itemBasePremium(item), 0);
43	
44	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
45	
46	const policyBasePremium = (items: Item[]): number => {
47	  const components = items.filter(isComponent);
48	  const nonComponents = items.filter((item) => !isComponent(item));
49	  const nonComponentBases = nonComponents.map(itemBasePremium);
50	  const componentGroupBases = [...groupByType(components).values()].map(
51	    componentGroupBasePremium,
52	  );
53	  return sum(nonComponentBases) + sum(componentGroupBases);
54	};
55	
56	const itemsSubtotal = (items: Item[]): number => {
57	  const components = items.filter(isComponent);
58	  const nonComponents = items.filter((item) => !isComponent(item));
59	
60	  const nonComponentPremiums = nonComponents.map((item) => {
61	    const base = itemBasePremium(item);
62	    const curseSurcharge = item.cursed ? base * 0.5 : 0;
63	    const highEnchSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
64	    return base + curseSurcharge + highEnchSurcharge + base * FIRST_INSURANCE_SURCHARGE_RATE;
65	  });
66	  const componentGroupPremiums = [...groupByType(components).values()].map(
67	    (group) => withFirstInsurance(componentGroupBasePremium(group)),
68	  );
69	
70	  return sum(nonComponentPremiums) + sum(componentGroupPremiums);
71	};
72	
73	const quotePremium = (step: Step, customer: Customer): number => {
74	  const subtotal = itemsSubtotal(step.items);
75	  const loyaltyDiscount =
76	    customer.yearsWithMHPCO >= 2 ? policyBasePremium(step.items) * 0.2 : 0;
77	  return Math.ceil(subtotal - loyaltyDiscount) + PROCESSING_FEE;
78	};
79	
80	export const runScenario = (input: unknown): unknown => {
81	  const { customer, steps } = input as Input;
82	  const results = steps.map((step) => ({ premium: quotePremium(step, customer) }));
83	  return { results };
84	};
