const quotePremium = (step: Step, customer: Customer, quoteIndex: number): number => {
  const subtotal = itemsSubtotal(step.items);
  const policyBase = policyBasePremium(step.items);
  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
  const followUpDiscount = quoteIndex >= 1 ? policyBase * 0.15 : 0;
  return Math.ceil(subtotal - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
};

export const runScenario = (input: unknown): unknown => {
  const { customer, steps } = input as Input;
  let quoteIndex = 0;
  const results = steps.map((step) => {
    const premium = quotePremium(step, customer, quoteIndex);
    if (step.op === "quote") quoteIndex++;
    return { premium };
  });
  return { results };
};
